SELECT 
FROM spc_data s
LEFT JOIN lots l ON l.id = s.lot_id
LEFT JOIN work_orders w ON w.id = s.work_order_id
WHERE 1 = 1

    AND s.lot_id = #{lotId}


    AND s.work_order_id = #{workOrderId}


    AND UPPER(s.parameter_name) = #{parameterName}

ORDER BY s.measured_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM spc_data s
WHERE 1 = 1

    AND s.lot_id = #{lotId}


    AND s.work_order_id = #{workOrderId}


    AND UPPER(s.parameter_name) = #{parameterName}

SELECT s.id, s.parameter_name, s.subgroup_no, s.x_bar, s.range_value, s.ucl, s.cl, s.lcl, TO_CHAR(s.measured_at, 'YYYY-MM-DD HH24:MI:SS') AS measured_at, l.lot_number, w.wo_number FROM spc_data s LEFT JOIN lots l ON l.id = s.lot_id LEFT JOIN work_orders w ON w.id = s.work_order_id WHERE 1 = 1
AND UPPER(s.parameter_name) = #{parameterName}
AND s.lot_id = #{lotId}
AND s.work_order_id = #{workOrderId}
ORDER BY s.subgroup_no ASC, s.measured_at ASC
